SELECT
n.news_id, n.special_report_id, n.alert_id,
n.title, n.content, n.video, n.platform, n.source,
n.publisher, n.publish_time, n.comment, n.region,
n.original_url, n.article_type, n.source_url, n.create_time,
c.sensitivity_level, c.sensitivity_label, c.sentiment_type
FROM news_data n
LEFT JOIN clear_data c ON n.news_id = c.news_id


        AND n.publish_time >= #{startTime}


        AND n.publish_time <= #{endTime}


        AND c.sensitivity_level IN

            #{level}



        AND n.source LIKE CONCAT('%', #{source}, '%')


        AND n.region LIKE CONCAT('%', #{region}, '%')



            AND (n.alert_id IN

                #{id}

            OR n.special_report_id IN

                #{id}

            )


            AND n.alert_id IN

                #{id}



            AND n.special_report_id IN

                #{id}




ORDER BY n.publish_time DESC
LIMIT #{pageSize} OFFSET #{offset}

SELECT
n.*,
c.sensitivity_level, c.sensitivity_label, c.sentiment_type
FROM news_data n
LEFT JOIN clear_data c
ON n.news_id = c.news_id
WHERE n.alert_id = #{reportId}
   OR n.special_report_id = #{reportId}
ORDER BY n.publish_time DESC
LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(1)
FROM news_data
WHERE alert_id = #{reportId}
   OR special_report_id = #{reportId}
